// Kill switch check
const enabled = $env.N8N_WORKFLOW_ELI_EMAIL_TRIAGE_ENABLED;
if (enabled === 'false' || enabled === '0') {
  return [{ json: { killed: true, reason: 'kill_switch_disabled' } }];
}

// --- HMAC signature validation (canonical JSON) ---
const crypto = require('crypto');
const secret = $env.N8N_ELI_WEBHOOK_SECRET;
const signature = $input.first().json.headers['x-webhook-signature'] || '';

function sortKeys(obj) {
  if (Array.isArray(obj)) return obj.map(sortKeys);
  if (obj !== null && typeof obj === 'object') {
    return Object.keys(obj).sort().reduce((acc, key) => {
      acc[key] = sortKeys(obj[key]);
      return acc;
    }, {});
  }
  return obj;
}

const body = $input.first().json.body;
const canonicalBody = JSON.stringify(sortKeys(body));
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(canonicalBody).digest('hex');

const sigBuf = Buffer.from(signature);
const expBuf = Buffer.from(expected);
if (sigBuf.length !== expBuf.length || !crypto.timingSafeEqual(sigBuf, expBuf)) {
  return [{ json: { killed: true, reason: 'hmac_validation_failed' } }];
}

// Extract and validate payload
const requestId = 'eli-triage-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const correlationId = body.correlation_id || 'n8n-eli-triage-' + Date.now();
const payloadHash = crypto.createHash('sha256').update(JSON.stringify(sortKeys({ email_id: body.email_id, from: body.from, subject: body.subject }))).digest('hex');
const idempotencyKey = crypto.createHash('sha256').update(requestId + 'eli.triage_email' + payloadHash).digest('hex');
return [{ json: { killed: false, requestId, correlationId, idempotencyKey, email_id: body.email_id, from: body.from, subject: body.subject, body_preview: body.body_preview, suite_id: body.suite_id, office_id: body.office_id } }];
